CREATE UNIQUE INDEX "IX_Blocks_BlockNumber_Hash" ON "Blocks" ("BlockNumber", "Hash");

CREATE INDEX "IX_Blocks_Hash" ON "Blocks" ("Hash");

CREATE INDEX "IX_Blocks_IsCanonical_BlockNumber" ON "Blocks" ("IsCanonical", "BlockNumber");

CREATE INDEX "IX_Blocks_ParentHash" ON "Blocks" ("ParentHash");

CREATE INDEX "IX_ChainStates_LastCanonicalBlockNumber" ON "ChainStates" ("LastCanonicalBlockNumber");

