CREATE UNIQUE INDEX "IX_Contracts_Name" ON "Contracts" ("Name");

CREATE INDEX "IX_TransactionLogs_Address" ON "TransactionLogs" ("Address");

CREATE INDEX "IX_TransactionLogs_EventHash" ON "TransactionLogs" ("EventHash");

CREATE INDEX "IX_TransactionLogs_IndexVal1" ON "TransactionLogs" ("IndexVal1");

CREATE INDEX "IX_TransactionLogs_IndexVal2" ON "TransactionLogs" ("IndexVal2");

CREATE INDEX "IX_TransactionLogs_IndexVal3" ON "TransactionLogs" ("IndexVal3");

CREATE UNIQUE INDEX "IX_TransactionLogs_TransactionHash_LogIndex" ON "TransactionLogs" ("TransactionHash", "LogIndex");

CREATE INDEX "IX_TransactionLogVmStacks_Address" ON "TransactionLogVmStacks" ("Address");

CREATE INDEX "IX_TransactionLogVmStacks_TransactionHash" ON "TransactionLogVmStacks" ("TransactionHash");

CREATE INDEX "IX_Transactions_AddressFrom" ON "Transactions" ("AddressFrom");

CREATE INDEX "IX_Transactions_AddressTo" ON "Transactions" ("AddressTo");

CREATE UNIQUE INDEX "IX_Transactions_BlockNumber_Hash" ON "Transactions" ("BlockNumber", "Hash");

CREATE INDEX "IX_Transactions_Hash" ON "Transactions" ("Hash");

CREATE INDEX "IX_Transactions_IsCanonical_BlockNumber" ON "Transactions" ("IsCanonical", "BlockNumber");

CREATE INDEX "IX_Transactions_NewContractAddress" ON "Transactions" ("NewContractAddress");

